const RANDOM_BARCODES = new Set<string>();

function generateBarcode(): string {
  const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
  let barcode: string;
  do {
    barcode = '';
    for (let i = 0; i < 10; i++) {
      barcode += chars[Math.floor(Math.random() * chars.length)];
    }
  } while (RANDOM_BARCODES.has(barcode));
  RANDOM_BARCODES.add(barcode);
  return barcode;
}

export async function seedFoods(): Promise<number> {
  const existing = await prisma.food.findMany({ select: { name: true } });
  const existingNames = new Set(existing.map((f) => f.name));
  const newFoods: Array<{
    name: string;
    brand: string;
    servingSize: string;
    calories: number;
    protein: number;
    carbs: number;
    fat: number;
    fiber: number | null;
    sugar: number | null;
    category: string;
    tags: string;
    barcode: string;
  }> = [];

  for (const food of [...FOODS, ...EXTRA_FOODS]) {
    if (existingNames.has(food.name)) continue;
    newFoods.push({
      name: food.name,
      brand: food.brand,
      servingSize: food.servingSize,
      calories: food.calories,
      protein: food.protein,
      carbs: food.carbs,
      fat: food.fat,
      fiber: food.fiber,
      sugar: food.sugar,
      category: food.category,
      tags: JSON.stringify(food.tags),
      barcode: generateBarcode(),
    });
  }

  if (newFoods.length > 0) {
    await prisma.food.createMany({ data: newFoods, skipDuplicates: true });
  }

  return newFoods.length;
}

if (import.meta.url === `file://${process.argv[1]}`) {
  seedFoods()
    .then((count) => {
      console.log(`Foods seeded: ${count}`);
      return prisma.$disconnect();
    })
    .catch((e) => {
      console.error(e);
      return prisma.$disconnect().then(() => process.exit(1));
    });
}

